			}
		}
	},
	"dataSources": {
		"ds_5X3yLWZm_ds_n1gCsBcD": {
			"name": "oil_volume_per_well",
			"options": {
				"enableSmartSources": true,
				"query": "| tstats fillnull_value=\"N/A\"\nsum(Main_Data.BORE_OIL_VOL) as Oil   \nFROM datamodel=OilGas.Main_Data  \nWHERE Main_Data.WELL_BORE_CODE=\"$selected_well$\"\nBY _time \n| stats sum(Oil) as Oil by _time\n| fillnull value=0 Oil\n| timechart sum(Oil) as \"Oil Volume\"\n\n",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_5n6dirJp_ds_yo4JZ91a": {
			"name": "data_quality_pre_well",
			"options": {
				"query": "| from datamodel:OilGas.Main_Data\n| search WELL_BORE_CODE=* \n| eval present=0\n| eval present=present + if(isnull('AVG_DP_TUBING') OR 'AVG_DP_TUBING'=0, 0, 1)\n| eval present=present + if(isnull('AVG_WHP_P') OR 'AVG_WHP_P'=0, 0, 1)\n| eval present=present + if(isnull('AVG_ANNULUS_PRESS') OR 'AVG_ANNULUS_PRESS'=0, 0, 1)\n| eval present=present + if(isnull('AVG_DOWNHOLE_PRESSURE') OR 'AVG_DOWNHOLE_PRESSURE'=0, 0, 1)\n| eval present=present + if(isnull('AVG_DOWNHOLE_TEMPERATURE') OR 'AVG_DOWNHOLE_TEMPERATURE'=0, 0, 1)\n| eval present=present + if(isnull('AVG_WHT_P') OR 'AVG_WHT_P'=0, 0, 1)\n| stats sum(present) as present_fields, count as total_events by WELL_BORE_CODE\n| eval total_possible_fields = total_events * 6\n| eval score=round((present_fields / total_possible_fields) * 100)\n| rangemap field=score low=0-49 medium=50-64 high=65-79 very_high=80-89 excellent=90-100\n| fields WELL_BORE_CODE, score\n| sort _- num(score)",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_7QxjSlar": {
			"name": "data_quality_timeline",
			"options": {
				"query": "| tstats \n    count as total_events \n    values(Main_Data.AVG_DP_TUBING) as AVG_DP_TUBING \n    values(Main_Data.AVG_WHP_P) as AVG_WHP_P \n    values(Main_Data.AVG_ANNULUS_PRESS) as AVG_ANNULUS_PRESS \n    values(Main_Data.AVG_DOWNHOLE_PRESSURE) as AVG_DOWNHOLE_PRESSURE \n    values(Main_Data.AVG_DOWNHOLE_TEMPERATURE) as AVG_DOWNHOLE_TEMPERATURE \n    values(Main_Data.AVG_WHT_P) as AVG_WHT_P \n    from datamodel=OilGas.Main_Data \n    where Main_Data.WELL_BORE_CODE=\"$selected_well$\"\n    by _time\n| eval present=0\n| eval present=present + if(isnull(AVG_DP_TUBING) OR AVG_DP_TUBING=0, 0, 1)\n| eval present=present + if(isnull(AVG_WHP_P) OR AVG_WHP_P=0, 0, 1)\n| eval present=present + if(isnull(AVG_ANNULUS_PRESS) OR AVG_ANNULUS_PRESS=0, 0, 1)\n| eval present=present + if(isnull(AVG_DOWNHOLE_PRESSURE) OR AVG_DOWNHOLE_PRESSURE=0, 0, 1)\n| eval present=present + if(isnull(AVG_DOWNHOLE_TEMPERATURE) OR AVG_DOWNHOLE_TEMPERATURE=0, 0, 1)\n| eval present=present + if(isnull(AVG_WHT_P) OR AVG_WHT_P=0, 0, 1)\n| eval total_possible_fields = total_events * 6\n| eval score=round((present / total_possible_fields) * 100)\n| timechart avg(score) as score\n| eval score=round(score)"
			},
			"type": "ds.search"
		},
		"ds_7xm83k6h_ds_HTgO1NqI_ds_u0T6HJ5g": {
			"name": "int_press_by_well",
			"options": {
				"enableSmartSources": true,
