				"query": "| tstats sum(Main_Data.BORE_OIL_VOL) as Oil_Production, \n         sum(Main_Data.BORE_WAT_VOL) as Water_Production, \n         values(Main_Data.WELL_TYPE) as Type\n         values(Main_Data.ON_STREAM_HRS) as Hours_On_Stream\n  from datamodel=OilGas.Main_Data\n  where Main_Data.WELL_BORE_CODE=\"$selected_well$\"\n  by Main_Data.WELL_BORE_CODE\n| rename Main_Data.WELL_BORE_CODE as WELL_BORE_CODE\n| lookup oilgas_assets_wells WELL_BORE_CODE OUTPUT FLOW_KIND\n| eval Status=upper(substr(FLOW_KIND, 1, 1)) . lower(substr(FLOW_KIND, 2))\n| eval Type=mvjoin(Type, \", \")\n| eval Planned_Production=round(Oil_Production * (0.9 + (random() % 20 / 100)), 2)\n| eval Hours_On_Stream=Hours_On_Stream * 100\n| table Status, Type, Oil_Production, Water_Production, Planned_Production, Hours_On_Stream\n| transpose\n| rename \"row 1\" as Value, column as Metric",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
